    default_categories = [
        "General",
        "Tours",
        "Aventura",
        "Gastronomia",
        "City Tour",
    ]
    existing_categories = list(
        Servicio.objects.exclude(categoria__isnull=True)
        .exclude(categoria__exact="")
        .values_list("categoria", flat=True)
        .distinct()
    )

