        slug = base_slug
        suffix = 2
        while ServicioCategoria.objects.filter(slug=slug).exists():
            slug = f"{base_slug}-{suffix}"
            suffix += 1
        ServicioCategoria.objects.get_or_create(
            nombre=name,
            defaults={"orden": index, "slug": slug},
        )


